issue_body:
### Operating System

win11

### Programming Language

JavaScript

### CCXT Version

4.5.5

### Description

According to [CCXT documentation](https://docs.ccxt.com/#/exchanges/hyperliquid?id=fetchdeposits):
- `params.until` (int) - "the latest time in ms to fetch withdrawals for" should work
- Should return filtered deposits up to the specified timestamp

##  **Actual Behavior** 
- `fetchDeposits()` with `until` parameter → 500 Internal Server Error
- `fetchDeposits()` without `until` parameter → Works fine
- `fetchDeposits()` with `since` parameter → Works fine

##  ** Code**
```javascript
const ccxt = require('ccxt');

async function testHyperLiquidUntilBug() {
    const exchange = new ccxt.hyperliquid({
        apiKey: 'your-key',
        secret: 'your-secret', 
        walletAddress: '0x...',
        sandbox: false
    });

    try {
        // ✅ This works fine - returns all deposits
        console.log('Testing fetchDeposits without until parameter...');
        const allDeposits = await exchange.fetchDeposits('USDC');
        console.log(`✅ Success: Got ${allDeposits.length} deposits`);

        // ✅ This works fine - returns deposits since timestamp
        console.log('Testing fetchDeposits with since parameter...');
        const depositsSince = await exchange.fetchDeposits('USDC', 1724025600000);
        console.log(`✅ Success: Got ${depositsSince.length} deposits since timestamp`);

        // ❌ This consistently fails with 500 Internal Server Error
        console.log('Testing fetchDeposits with until parameter...');
        const depositsUntil = await exchange.fetchDeposits('USDC', null, 10, {
            until: 1724025600000  // Valid past timestamp
        });
        console.log(`✅ Success: Got ${depositsUntil.length} deposits until timestamp`);

    } catch (error) {
        console.error('❌ Error:', error.constructor.name);
        console.error('❌ Message:', error.message);
        // This will throw: ExchangeNotAvailable: hyperliquid POST https://api.hyperliquid.xyz/info 500 Internal Server Error null
    }
}

testHyperLiquidUntilBug();
```

Error Details
```
ExchangeNotAvailable: hyperliquid POST https://api.hyperliquid.xyz/info 500 Internal Server Error null
    at hyperliquid.handleHttpStatusCode
    at hyperliquid.fetchDeposits
```

am i doing something wrong? i went into the actual source code and i dont see why it could be failing on my side.

