async function main() {
  const exchange = new ccxt.okex();
  const symbol = "BTC/USDT:USDT";
  const hour = 3600000;

  const history = await exchange.fetchFundingRateHistory(symbol);
  const last = history[history.length - 1];
  const second_last = history[history.length - 2];
  const diff = last["timestamp"] - second_last["timestamp"];
  const hours = diff / hour;
  console.log(hours);
}

main();
